class Admin_Model_Announcement extends Admin_Model_Base_Announcement {

    const TYPE_INFO = 'info';
    const TYPE_SUCCESS = 'success';
    const TYPE_WARNING = 'warning';
    const TYPE_ERROR = 'error';

    const COOKIE = 'announcement';

    public function save(Doctrine_Connection $conn = null) {
        if (!$this->Hash)
            $this->Hash = uniqid();

        parent::save($conn);
    }

    /**
     * Vratí typy oznámení
     * @param bool $onlyKeys
     * @return array
     */
    public static function getTypes(bool $onlyKeys = false): array {
        $types = [
            self::TYPE_INFO => translate('Informace'),
            self::TYPE_SUCCESS => translate('Úspěch'),
            self::TYPE_WARNING => translate('Varování'),
            self::TYPE_ERROR => translate('Chyba'),
        ];

        return $onlyKeys?array_keys($types):$types;
    }

    /**
     * @param mixed $value
     * @param string $column
     * @return self|null
     */
    public static function getAnnouncement($value, string $column = "ID"): ?self {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Announcement object');
        $query->where("object.{$column} = ?", $value);

        return $query->fetchOne()??null;
    }

    /**
     * @param string $hash
     * @return self|null
     */
    public static function getAnnouncementByHash(string $hash): ?self {
        return self::getAnnouncement($hash, 'Hash');
    }

    /**
     * @param EshopModel|null $eshop
     * @return array|Doctrine_Collection|Admin_Model_Announcement[]
     * @throws Doctrine_Query_Exception
     */
    public static function getActiveAnnouncements(?EshopModel $eshop = null) {
        if (!$eshop)
            $eshop = Eshop::getInstance()->getEshop();

        $date = date('Y-m-d');

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Announcement object');
        $query->addWhere('object.Eshop_ID = ?');
        $query->addWhere('object.DateFrom IS NULL OR object.DateFrom <= ?');
        $query->addWhere('object.DateTo IS NULL OR object.DateTo > ?');
        $query->addWhere('IFNULL(object.Active,0) > 0');

        return $query->execute([$eshop->ID, $date, $date]);
    }

    /**
     * @param EshopModel|null $eshop
     * @return self|null
     * @throws Doctrine_Query_Exception
     */
    public static function getActiveAnnouncement(?EshopModel $eshop = null): ?self {
        if (!$announcement = self::getActiveAnnouncements($eshop)->getFirst())
            return null;

        return $announcement;
    }

    /**
     * @param EshopModel|null $eshop
     * @return self|null
     * @throws Doctrine_Query_Exception
     */
    public static function getActiveEmailAnnouncement(?EshopModel $eshop = null): ?string {
        $announcement = self::getActiveAnnouncement($eshop);
        if (!$announcement || !$announcement->InEmail)
            return null;

        return $announcement->Content;
    }

    /**
     * Vrací, zda bylo upozornění již zavřeno
     * @return bool
     */
    public function isRead(): bool {
        if (!$this->Hash)
            return true;

        return in_array($this->Hash, json_decode($_COOKIE[self::COOKIE]??'[]'));
    }
}